#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
inline int Min(int x,int y){return x<y?x:y;}
const int N=80,INF=0x3f3f3f3f;
int dp[N][N][N],P[N],s[N];
struct Sort
{
	int val,key,cst;
	inline bool operator <(const Sort &x)const {return val^x.val?val<x.val:key<x.key;}
}Q[N];
int main()
{
	int n=read(),K=read();rep(1,n,i)Q[i].val=read();
	rep(1,n,i)Q[i].key=P[i]=read();rep(1,n,i)Q[i].cst=read();
	std::sort(Q+1,Q+n+1);std::sort(P+1,P+n+1);
	rep(1,n,i)
	{
		int l=1,r=n,mid,res=1;
		while(l<=r)P[mid=(l+r)>>1]<=Q[i].key?(l=mid+1,res=mid):(r=mid-1);
		Q[i].key=res;s[i]=s[i-1]+Q[i].cst;
	}
	memset(dp,0x3f,sizeof(dp));
	rep(1,n+1,i)rep(1,n,j)dp[i][i-1][j]=0;
	rep(1,n,T)
	{
		for(register int l=1,r=T;r<=n;++l,++r)
		{
			rep(1,n,k)rep(l,r,t)
			{
				if(Q[t].key>=k)dp[l][r][k]=Min(dp[l][r][k],dp[l][t-1][Q[t].key]+dp[t+1][r][Q[t].key]+s[r]-s[l-1]);
				dp[l][r][k]=Min(dp[l][r][k],dp[l][t-1][k]+dp[t+1][r][k]+s[r]-s[l-1]+K);
			}
		}
	}
